import { cpSync, existsSync, mkdirSync, rmSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";

const ROOT = resolve(".");
const OUT = resolve("dist-public");
const INCLUDE = [
  "README.md",
  "LICENSE",
  "SECURITY.md",
  "docs/ARCHITECTURE_OVERVIEW.md",
  "docs/COMPILER_ERROR_CODES.md",
  "docs/DEPLOY_GUIDE.md",
  "docs/GOVERNANCE_VERSIONING_POLICY.md",
  "docs/LANGUAGE_V1_MIGRATION.md",
  "docs/LTS_POLICY.md",
  "docs/OBSERVABILITY.md",
  "docs/RELEASE_PROCESS.md",
  "docs/ROLLOUT_GUIDE.md",
  "docs/SUPPORT_MATRIX.md",
  "docs/TROUBLESHOOTING.md",
  "docs/REPO_BOUNDARY_STRATEGY.md",
  "spec/LANGUAGE_V1_SPEC.md",
  "examples/fullstack",
  "examples/startup-mvp"
];

rmSync(OUT, { recursive: true, force: true });
mkdirSync(OUT, { recursive: true });

for (const rel of INCLUDE) {
  const from = join(ROOT, rel);
  const to = join(OUT, rel);
  if (!existsSync(from)) continue;
  mkdirSync(dirname(to), { recursive: true });
  cpSync(from, to, { recursive: true });
}

writeFileSync(
  join(OUT, "PUBLIC_BUNDLE_README.md"),
  [
    "# FastScript Public Bundle",
    "",
    "This bundle contains the approved public-facing docs and examples subset.",
    "It intentionally excludes protected compiler/platform internals and private AI assets.",
    "",
    "Generated by `npm run public:bundle`."
  ].join("\n"),
  "utf8"
);

console.log(`public bundle ready: ${OUT}`);
